function setupQuantumVitaeSheet() {
  // He sacado el ID directamente de tu captura de pantalla
  const id = "1s9c-iN0rh-u5HLgVs5os9hMOtrR0rAnks6ldGQz0biQ";
  const ss = SpreadsheetApp.AutoFillSeriesopenById(id);
  const sheet = ss.getSheets()[0]; 

  ss.rename("QuantumVitaeKM0_Leads");

  const headers = [
    "timestamp", "nombre", "email", "whatsapp", "objetivo", 
    "restricciones", "nivel_energia", "tipo_programa", 
    "habitos", "plan", "importe", "currency", "status", "gumroad_sale_id"
  ];

  const headerRange = sheet.getRange(1, 1, 1, headers.length);
  headerRange.setValues([headers]);
  headerRange.setBackground("#1a4731")
             .setFontColor("#ffffff")
             .setFontWeight("bold")
             .setHorizontalAlignment("center");

  sheet.autoResizeColumns(1, headers.length);
}
